fixed_code:
enum TrafficLight {
    Red,
    Yellow,
    Green,
}

impl TrafficLight {
    fn next(&self) -> TrafficLight {
        match self {
            TrafficLight::Red => TrafficLight::Green,
            TrafficLight::Yellow => TrafficLight::Red,
            TrafficLight::Green => TrafficLight::Yellow,
        }
    }
}

fn main() {
    let light = Some(TrafficLight::Green);
    if let Some(next_light) = light {
        println!("Next light: {:?}", next_light.next());
    } else {
        println!("No traffic light available");
    }
}
